"use client";

import { useAudio } from '@/context/AudioContext';
import styles from './NewReleases.module.css';

const albums = [
    { id: 1, title: 'Neon Drift', subtitle: 'Synthwave', cover: '/images/albums/neon_drift.png' },
    { id: 2, title: 'Midnight', subtitle: 'Electronic', cover: '/images/albums/midnight.png' },
    { id: 3, title: 'Cyber City', subtitle: 'Cyberpunk', cover: '/images/albums/cyber_city.png' },
    { id: 4, title: 'Deep Space', subtitle: 'Ambient', cover: '/images/albums/deep_space.png' },
];

export default function NewReleases() {
    const { playTrack } = useAudio();

    const handlePlayMain = () => {
        playTrack({
            id: 5,
            title: 'STARBOY',
            subtitle: 'Pop/R&B',
            cover: '/images/albums/starboy.png'
        });
    };

    return (
        <section className={styles.section}>
            <div className={styles.container}>

                <div className={styles.header}>
                    <h2 className={styles.title}>
                        Listen To <span className={styles.highlight}>New Release Music</span> And<br />
                        Download It For Offline Listening<br />
                        Anytime, Anywhere
                    </h2>
                    <button className={styles.btnPremium}>
                        <span>Explore More</span>
                        <div className={styles.shine}></div>
                    </button>
                </div>

                <div className={styles.grid}>
                    {/* Main Album (Left side, larger) */}
                    <div className={`${styles.card} ${styles.mainCard}`} onClick={handlePlayMain}>
                        <img
                            src="/images/albums/starboy.png"
                            alt="Starboy"
                            className={styles.albumCover}
                        />
                        <div className={styles.cardOverlay}>
                            <div className={styles.playBtn}>
                                <svg viewBox="0 0 24 24" fill="currentColor"><path d="M8 5v14l11-7z"></path></svg>
                            </div>
                        </div>
                        <div className={styles.cardInfo}>
                            <h3>STARBOY</h3>
                        </div>
                    </div>

                    {/* Right side Grid */}
                    <div className={styles.subGrid}>
                        {/* Top right single album */}
                        {/* Top right single album */}
                        <div className={`${styles.card} ${styles.topRightAlbum}`} style={{ animationDelay: '0.2s' }}>
                            <img
                                src="/images/albums/top_hit.png"
                                alt="Top Hit"
                                className={styles.albumCover}
                            />
                            <div className={styles.cardOverlay}>
                                <div className={styles.cardInfo}>
                                    <h4>Top Hit</h4>
                                </div>
                            </div>
                        </div>
                        {/* Bottom 4 albums */}
                        {/* Bottom 4 albums */}
                        <div className={styles.fourAlbumsGrid}>
                            {albums.map((album, index) => (
                                <div
                                    key={album.id}
                                    className={styles.card}
                                    onClick={() => playTrack(album)}
                                    style={{ animationDelay: `${0.3 + (index * 0.1)}s` }}
                                >
                                    <img src={album.cover} alt={album.title} className={styles.albumCover} />
                                    <div className={styles.cardOverlay}>
                                        <div className={styles.playBtnSmall}>
                                            <svg viewBox="0 0 24 24" fill="currentColor"><path d="M8 5v14l11-7z"></path></svg>
                                        </div>
                                    </div>
                                    <div className={styles.smallCardInfo}>
                                        <h4>{album.title}</h4>
                                        <p>{album.subtitle}</p>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>

                </div>
            </div>
        </section>
    );
}

"use client";

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';

export type Track = {
    id: number;
    title: string;
    subtitle: string;
    cover: string;
};

interface AudioContextType {
    isPlaying: boolean;
    currentTrack: Track | null;
    progress: number;
    togglePlay: () => void;
    playTrack: (track: Track) => void;
    nextTrack: () => void;
    prevTrack: () => void;
}

const AudioContext = createContext<AudioContextType | undefined>(undefined);

const defaultTracks: Track[] = [
    { id: 1, title: 'Alan Jackson', subtitle: 'Country', cover: 'https://images.unsplash.com/photo-1598387181032-a310322db117?w=300&q=80' },
    { id: 2, title: 'Trap Music', subtitle: 'Hip Hop', cover: 'https://images.unsplash.com/photo-1508215885820-4585e5610ea0?w=300&q=80' },
    { id: 3, title: 'Strange', subtitle: 'Electronic', cover: 'https://images.unsplash.com/photo-1614613535308-eb5fbd3d2c17?w=300&q=80' },
    { id: 4, title: 'Classic Rock', subtitle: 'Rock', cover: 'https://images.unsplash.com/photo-1511671782779-c97d3d27a1d4?w=300&q=80' },
    { id: 5, title: 'WAY TURN', subtitle: 'Pop', cover: 'https://images.unsplash.com/photo-1493225457124-a1a2a5f0a41e?w=500&q=80' }
];

export const AudioProvider = ({ children }: { children: ReactNode }) => {
    const [isPlaying, setIsPlaying] = useState(false);
    const [currentTrack, setCurrentTrack] = useState<Track | null>(defaultTracks[4]); // default to WAY TURN
    const [progress, setProgress] = useState(0);

    // Simulate progress
    useEffect(() => {
        let interval: NodeJS.Timeout;
        if (isPlaying) {
            interval = setInterval(() => {
                setProgress((prev) => {
                    if (prev >= 100) {
                        nextTrack();
                        return 0;
                    }
                    return prev + 0.5; // simulate some speed
                });
            }, 1000);
        }
        return () => clearInterval(interval);
    }, [isPlaying]);

    const togglePlay = () => setIsPlaying(!isPlaying);

    const playTrack = (track: Track) => {
        setCurrentTrack(track);
        setIsPlaying(true);
        setProgress(0);
    };

    const nextTrack = () => {
        if (!currentTrack) return;
        const currentIndex = defaultTracks.findIndex(t => t.id === currentTrack.id);
        const nextIndex = (currentIndex + 1) % defaultTracks.length;
        setCurrentTrack(defaultTracks[nextIndex]);
        setProgress(0);
    };

    const prevTrack = () => {
        if (!currentTrack) return;
        const currentIndex = defaultTracks.findIndex(t => t.id === currentTrack.id);
        const prevIndex = currentIndex === 0 ? defaultTracks.length - 1 : currentIndex - 1;
        setCurrentTrack(defaultTracks[prevIndex]);
        setProgress(0);
    };

    return (
        <AudioContext.Provider value={{ isPlaying, currentTrack, progress, togglePlay, playTrack, nextTrack, prevTrack }}>
            {children}
        </AudioContext.Provider>
    );
};

export const useAudio = () => {
    const context = useContext(AudioContext);
    if (context === undefined) {
        throw new Error('useAudio must be used within an AudioProvider');
    }
    return context;
};
